foreach (var m in ccb.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly).Where(m => !m.IsSpecialName))
    Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");

// Check FunctionInvocationOptions
Console.WriteLine("\n=== FunctionInvocationOptions (if exists) ===");
var fioType = typeof(ChatOptions).Assembly.GetTypes().FirstOrDefault(t => t.Name.Contains("FunctionInvocation"));
if (fioType != null)
    foreach (var p in fioType.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  {p.Name}: {p.PropertyType.Name}");

// Check extension methods on ChatClientBuilder from MEAI assemblies
var meaiAsm = typeof(ChatClientBuilder).Assembly;
Console.WriteLine($"\n=== Extension methods from {meaiAsm.GetName().Name} ===");
foreach (var t in meaiAsm.GetExportedTypes().Where(t => t.IsAbstract && t.IsSealed)) // static classes
{
    var extMethods = t.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.GetParameters().Length > 0 && m.GetParameters()[0].ParameterType == typeof(ChatClientBuilder));
    foreach (var m in extMethods)
        Console.WriteLine($"  {t.Name}.{m.Name}({string.Join(", ", m.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name))})");
