sealed class ResearchTools
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Search the web for information. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: {query}");

        try
        {
            var encoded = WebUtility.UrlEncode(query);
            var html = await Http.GetStringAsync(
                $"https://html.duckduckgo.com/html/?q={encoded}", cancellationToken);

            var results = Regex.Matches(html,
                @"<a[^>]+class=""result__a""[^>]+href=""(?<url>[^""]+)""[^>]*>(?<title>.*?)</a>.*?<a[^>]+class=""result__snippet""[^>]*>(?<snippet>.*?)</a>",
                RegexOptions.Singleline);

            if (results.Count == 0)
            {
                return "No search results found.";
            }

            var output = results
                .Cast<Match>()
                .Take(5)
                .Select((m, i) =>
                {
                    var title = StripHtml(m.Groups["title"].Value);
                    var url = WebUtility.UrlDecode(m.Groups["url"].Value);
                    var snippet = StripHtml(m.Groups["snippet"].Value);
                    return $"{i + 1}. {title}\n   URL: {url}\n   {snippet}";
                });

            return string.Join("\n\n", output);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL.")]
    public async Task<string> FetchWebPage(
        [Description("The URL of the page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  📄 Fetching: {url}");

        try
        {
            var html = await Http.GetStringAsync(url, cancellationToken);

            // Strip scripts, styles, and tags to get readable text
            html = Regex.Replace(html, @"<script[^>]*>[\s\S]*?</script>", "", RegexOptions.IgnoreCase);
            html = Regex.Replace(html, @"<style[^>]*>[\s\S]*?</style>", "", RegexOptions.IgnoreCase);
            var text = StripHtml(html);

            // Collapse whitespace and limit length
            text = Regex.Replace(text, @"\s+", " ").Trim();
            const int maxLength = 3000;
            if (text.Length > maxLength)
            {
                text = text[..maxLength] + "... [truncated]";
            }

            return string.IsNullOrWhiteSpace(text) ? "Page contained no readable text." : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    [Description("Save a research note with a title and content. Use this to record important findings.")]
    public string SaveNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The note content with key findings")] string content)
    {
        _notes.Add((title, content));
        Console.WriteLine($"  📝 Note saved: {title}");
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n\n---\n\n", _notes.Select((n, i) =>
            $"Note {i + 1}: {n.Title}\n{n.Content}"));
    }

    private static string StripHtml(string html) =>
        WebUtility.HtmlDecode(Regex.Replace(html, @"<[^>]+>", " "));
}

